import{_ as t,o as n,c as a,a2 as o}from"./chunks/framework.ufzXw1qY.js";const h=JSON.parse('{"title":"Automated SEO Content Pipeline","description":"","frontmatter":{},"headers":[],"relativePath":"best-practices/seo-pipeline.md","filePath":"best-practices/seo-pipeline.md"}'),s={name:"best-practices/seo-pipeline.md"};function i(r,e,l,d,p,c){return n(),a("div",null,[...e[0]||(e[0]=[o(`<hr><h2 id="title-automated-seo-content-pipelinedescription-proof-of-work-blog-publishing-from-merged-prs-using-n8n-and-cloudflare-pages" tabindex="-1">title: Automated SEO Content Pipeline description: Proof-of-work blog publishing from merged PRs using n8n and Cloudflare Pages. <a class="header-anchor" href="#title-automated-seo-content-pipelinedescription-proof-of-work-blog-publishing-from-merged-prs-using-n8n-and-cloudflare-pages" aria-label="Permalink to &quot;title: Automated SEO Content Pipeline
description: Proof-of-work blog publishing from merged PRs using n8n and Cloudflare Pages.&quot;">​</a></h2><h1 id="automated-seo-content-pipeline" tabindex="-1">Automated SEO Content Pipeline <a class="header-anchor" href="#automated-seo-content-pipeline" aria-label="Permalink to &quot;Automated SEO Content Pipeline&quot;">​</a></h1><p>OpenSIN AI Agent’s SEO pipeline automatically turns <strong>real merged pull requests</strong> into high‑quality blog posts, avoiding generic AI fluff and satisfying Google’s E‑E‑A‑T guidelines.</p><h2 id="architecture-deep-dive" tabindex="-1">Architecture Deep Dive <a class="header-anchor" href="#architecture-deep-dive" aria-label="Permalink to &quot;Architecture Deep Dive&quot;">​</a></h2><h3 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐   webhook   ┌─────────────────────┐</span></span>
<span class="line"><span>│  GitHub Repo    │────────────▶│  n8n (OCI VM)      │</span></span>
<span class="line"><span>│  (any OpenSIN)  │             │  Workflow sq7YR8...│</span></span>
<span class="line"><span>└─────────────────┘             └─────────┬───────────┘</span></span>
<span class="line"><span>                                            │</span></span>
<span class="line"><span>                                  ┌──────────▼──────────┐</span></span>
<span class="line"><span>                                  │  Function Nodes     │</span></span>
<span class="line"><span>                                  │  - Generate Draft   │</span></span>
<span class="line"><span>                                  │  - Humanize + b64   │</span></span>
<span class="line"><span>                                  │  - Commit (HTTPS)   │</span></span>
<span class="line"><span>                                  └──────────┬───────────┘</span></span>
<span class="line"><span>                                            │</span></span>
<span class="line"><span>                                  ┌──────────▼──────────┐</span></span>
<span class="line"><span>                                  │  GitHub API (PUT)   │</span></span>
<span class="line"><span>                                   │  OpenSIN-AI/        │</span></span>
<span class="line"><span>                                   │  Biz-SIN-Blog-Posts │</span></span>
<span class="line"><span>                                  └──────────┬───────────┘</span></span>
<span class="line"><span>                                            │</span></span>
<span class="line"><span>                                  ┌──────────▼──────────┐</span></span>
<span class="line"><span>                                  │  Cloudflare Pages   │</span></span>
<span class="line"><span>                                  │  blog.opensin.ai    │</span></span>
<span class="line"><span>                                  └─────────────────────┘</span></span></code></pre></div><h3 id="why-n8n-function-nodes-instead-of-http-request" tabindex="-1">Why n8n Function Nodes Instead of HTTP Request? <a class="header-anchor" href="#why-n8n-function-nodes-instead-of-http-request" aria-label="Permalink to &quot;Why n8n Function Nodes Instead of HTTP Request?&quot;">​</a></h3><p>Initially we tried the built‑in HTTP Request node. Problems encountered:</p><table tabindex="0"><thead><tr><th>Problem</th><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>JSON body encoding</td><td>GitHub received malformed JSON</td><td>Switch to raw body expression: <code>&amp;#123;&amp;#123; JSON.stringify({...}) &amp;#125;&amp;#125;</code></td></tr><tr><td>Content‑Type conflicts</td><td>Node sent form‑urlencoded</td><td>Set <code>contentType: raw</code> and <code>sendBody: true</code>.</td></tr><tr><td>Base64 handling</td><td>Needed to embed <code>$json.content_base64</code></td><td>Expression <code>&amp;#123;&amp;#123; $json.content_base64 &amp;#125;&amp;#125;</code> works.</td></tr><tr><td>Reliability</td><td>Various edge cases</td><td>Final solution: replace HTTP node with Function node using <code>https</code> – full control.</td></tr></tbody></table><h3 id="determinism-guarantee" tabindex="-1">Determinism Guarantee <a class="header-anchor" href="#determinism-guarantee" aria-label="Permalink to &quot;Determinism Guarantee&quot;">​</a></h3><ul><li>All text generation occurs <strong>synchronously</strong> inside Function nodes.</li><li>No external network calls except final HTTPS commit.</li><li>Given same PR data, Markdown output is identical.</li><li>Avoids LLM rate limits, token rotation failures, non‑deterministic phrasing.</li></ul><h2 id="configuration-reference" tabindex="-1">Configuration Reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Value (Placeholder)</th></tr></thead><tbody><tr><td><strong>n8n API Key</strong></td><td><code>&lt;YOUR_N8N_API_KEY&gt;</code></td></tr><tr><td><strong>n8n Host</strong></td><td>Internal self-hosted n8n endpoint (see owning infra repo)</td></tr><tr><td><strong>Workflow ID</strong></td><td><code>sq7YR8vkdPf3usnz</code></td></tr><tr><td><strong>GitHub Token</strong></td><td><code>&lt;YOUR_GITHUB_TOKEN&gt;</code> (repo scope) – store in n8n Credentials</td></tr><tr><td><strong>Blog Repo</strong></td><td><code>OpenSIN-AI/Biz-SIN-Blog-Posts</code></td></tr><tr><td><strong>Cloudflare Pages</strong></td><td>Project <code>opensin-blog</code> → Domain <code>blog.opensin.ai</code></td></tr><tr><td><strong>Trigger Path</strong></td><td><code>/webhook/blog-publish</code> (POST)</td></tr></tbody></table><h2 id="monitoring-alerts" tabindex="-1">Monitoring &amp; Alerts <a class="header-anchor" href="#monitoring-alerts" aria-label="Permalink to &quot;Monitoring &amp; Alerts&quot;">​</a></h2><ul><li><strong>Execution history</strong>: via n8n API <code>/api/v1/executions?workflowId=sq7YR8vkdPf3usnz</code>.</li><li><strong>Suggested alerts</strong>: workflow failure, no success in 24 h, blog repo inactive.</li></ul><h2 id="future-improvements" tabindex="-1">Future Improvements <a class="header-anchor" href="#future-improvements" aria-label="Permalink to &quot;Future Improvements&quot;">​</a></h2><ul><li>[ ] Idempotent updates via SHA lookup.</li><li>[ ] Dynamic PR number in filename and message.</li><li>[ ] Configurable post template stored in Google Docs or Markdown file.</li><li>[ ] Enriched content: code snippets, changed files list, commit SHAs.</li><li>[ ] Tag inference from file paths.</li><li>[ ] Scheduled publishing (SEO‑friendly hours).</li><li>[ ] CI test suite for Function nodes.</li><li>[ ] Move GitHub token to n8n Credential Store.</li><li>[ ] Add webhook secret for authentication.</li></ul><h2 id="related-documents" tabindex="-1">Related Documents <a class="header-anchor" href="#related-documents" aria-label="Permalink to &quot;Related Documents&quot;">​</a></h2><ul><li>OpenSIN‑overview → <code>docs/seo-pipeline.md</code> (high‑level overview).</li><li>n8n Workflow Template → <code>n8n-workflows/auto-blog-publisher.json</code>.</li><li>GitHub API – Create or update file contents: <a href="https://docs.github.com/en/rest/repos/contents#create-or-update-file-contents" target="_blank" rel="noreferrer">https://docs.github.com/en/rest/repos/contents#create-or-update-file-contents</a></li><li>Cloudflare Pages – Deploy from Git: <a href="https://developers.cloudflare.com/pages/" target="_blank" rel="noreferrer">https://developers.cloudflare.com/pages/</a></li></ul><hr><p><em>Document version:</em> 2026‑04‑10<br><em>Maintainer:</em> sin‑zeus<br><em>Review cycle:</em> Monthly or after any workflow change.</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>n8n CI/CD</strong></td><td>0.0</td><td>Self-hosted auf OCI VM</td></tr><tr><td><strong>Box.com Storage</strong></td><td>0.0</td><td>Artefakte zu Box.com</td></tr></tbody></table>`,25)])])}const m=t(s,[["render",i]]);export{h as __pageData,m as default};
